"""Domain model for the in-memory relational database.

The "nouns": the type vocabulary (`ColumnType`), one typed-exception family
(`DatabaseError` + subclasses), the value objects (`Column`, `Schema`, `Row`),
and the one rich entity — `Table`.

The single most important rule this file enforces: **a table's secondary
indexes stay perfectly consistent with its rows on EVERY mutation.** That rule
is intrinsic to the table (it is the only object that owns both the rows AND the
indexes), so `Table` — not the service — performs every row write together with
its index updates. The service can never insert a row and "forget" to index it,
because there is no public way to touch rows except through these methods.

🎙️ "I made the Table the single owner of both the rows and their indexes, so
keeping them in sync is impossible to get wrong — every insert/update/delete
touches both in one place, under one lock."
"""

from dataclasses import dataclass
from enum import Enum
from typing import Any

from predicates import HashIndex


# ── VOCABULARY ───────────────────────────────────────────────────────────────
class ColumnType(Enum):
    INT = "INT"
    STR = "STR"
    BOOL = "BOOL"

    def accepts(self, value: Any) -> bool:
        # WHY: bool is a SUBCLASS of int in Python, so a naive isinstance(x, int)
        #      would let True sneak into an INT column. We check bool explicitly
        #      and exclude it from INT so the types stay honest.
        if self is ColumnType.INT:
            return isinstance(value, int) and not isinstance(value, bool)
        if self is ColumnType.BOOL:
            return isinstance(value, bool)
        return isinstance(value, str)        # ColumnType.STR


# ── EXCEPTIONS (one base, one subclass per failure mode) ─────────────────────
class DatabaseError(Exception):
    """Base for every error this database raises — callers catch one type."""


class SchemaError(DatabaseError):
    """A row/change violates the schema: missing column, unknown column, wrong type."""


class TableNotFoundError(DatabaseError):
    """An operation named a table that does not exist."""


class TableExistsError(DatabaseError):
    """create_table() named a table that already exists."""


class ColumnNotFoundError(DatabaseError):
    """A predicate, projection, or index referenced a column not in the schema."""


class IndexExistsError(DatabaseError):
    """create_index() named a column that is already indexed."""


# ── VALUE OBJECTS ────────────────────────────────────────────────────────────
@dataclass(frozen=True)
class Column:
    """A typed column definition. Immutable — a schema never changes after creation."""
    name: str
    type: ColumnType


class Schema:
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The table's contract for what a valid row looks like. It is the single
    # place type-checking lives, so insert AND update validate the same way.
    def __init__(self, columns: list[Column]) -> None:
        if not columns:
            raise SchemaError("a schema needs at least one column")
        names = [c.name for c in columns]

        if len(names) != len(set(names)):
            raise SchemaError(f"duplicate column names in schema: {names}")
        self._columns: tuple[Column, ...] = tuple(columns)
        self._by_name: dict[str, Column] = {c.name: c for c in columns}

    def column_names(self) -> list[str]:
        return [c.name for c in self._columns]

    def has(self, name: str) -> bool:
        return name in self._by_name

    def validate_row(self, values: dict[str, Any]) -> dict[str, Any]:
        """Check a full row on insert: every column present, right type, no extras.

        Returns a normalized dict (columns in schema order). Raises SchemaError.
        """
        missing = set(self._by_name) - set(values)
        if missing:
            raise SchemaError(f"row is missing columns: {sorted(missing)}")
        unknown = set(values) - set(self._by_name)
        if unknown:
            raise SchemaError(f"row has unknown columns: {sorted(unknown)}")
        normalized: dict[str, Any] = {}
        for col in self._columns:
            value = values[col.name]
            if not col.type.accepts(value):
                raise SchemaError(
                    f"column {col.name!r} expects {col.type.value}, got {value!r}"
                )
            normalized[col.name] = value
        return normalized

    def validate_changes(self, changes: dict[str, Any]) -> None:
        """Check a partial update: each named column exists and the new value fits."""
        if not changes:
            raise SchemaError("update needs at least one column to change")
        for name, value in changes.items():
            col = self._by_name.get(name)
            if col is None:
                raise SchemaError(f"cannot update unknown column {name!r}")
            if not col.type.accepts(value):
                raise SchemaError(
                    f"column {name!r} expects {col.type.value}, got {value!r}"
                )


@dataclass
class Row:
    """One stored record: a stable row id + its column->value map (mutable for update)."""
    rid: int
    values: dict[str, Any]


# ── ENTITY: the Table (owns rows + indexes + their consistency) ──────────────
class Table:
    # ── WHY THIS CLASS ──────────────────────────────────────────────────────
    # The heart of the model. It owns the rows AND every secondary index, so it
    # is the natural home for the rule "index always matches rows": each write
    # method updates both in one step. Nothing outside this class can mutate a
    # row, so the index can never drift out of sync.
    def __init__(self, name: str, schema: Schema) -> None:
        self.name = name
        self.schema = schema
        self._rows: dict[int, Row] = {}
        self._indexes: dict[str, HashIndex] = {}
        self._next_id = 0                     # plain counter — see §9: the race point

    # ── index management ──
    def add_index(self, column: str) -> None:
        if not self.schema.has(column):
            raise ColumnNotFoundError(f"cannot index unknown column {column!r}")
        if column in self._indexes:
            raise IndexExistsError(f"column {column!r} is already indexed")
        index = HashIndex(column)
        for row in self._rows.values():       # backfill from rows already present
            index.add(row.values[column], row.rid)
        self._indexes[column] = index

    def index_for(self, column: str) -> HashIndex | None:
        return self._indexes.get(column)

    # ── row mutations (each keeps EVERY index in sync) ──
