        # WHY: a missing/None cell is never "in range" — guard before comparing,
        #      otherwise `None <= x` would raise a TypeError on Python 3.
        return v is not None and self.low <= v <= self.high

    def columns(self) -> set[str]:
        return {self.column}
    # no eq_conditions(): a range is not an equality, so the planner falls back to scan


class And(Predicate):
    """All sub-predicates must match. Carries forward its children's eq-conditions."""

    def __init__(self, *parts: Predicate) -> None:
        # An empty And is the well-defined "match everything" predicate
        # (all() of nothing is True) — no need to special-case it as an error.
        self.parts = parts

    def matches(self, values: dict[str, Any]) -> bool:
        return all(p.matches(values) for p in self.parts)

    def columns(self) -> set[str]:
        return set().union(*(p.columns() for p in self.parts))

    def eq_conditions(self) -> list[tuple[str, Any]]:
        # WHY: an AND like `age == 30 AND city in [..]` is index-usable on `age`
        #      — collect every child's equality so the planner can pick any one
        #      that happens to be indexed, then matches() re-checks the rest.
        out: list[tuple[str, Any]] = []
        for part in self.parts:
            out.extend(part.eq_conditions())
        return out
